SELECT S.GENERO FROM SERVIDOR_PROJ SP JOIN PROJ P ON P.PK = SP.FK_PROJ JOIN SERVIDOR S ON S.PK_SIAPE = SP.FK_SIAPE WHERE LOWER(P.TIPO_PROJETO) = LOWER('pesquisa') AND LOWER(COALESCE(P.AREA_CONHECIMENTO, '')) LIKE '%hist%' AND P.DATA_TERMINO >= DATE('now', '-5 years') AND P.DATA_INICIO <= DATE('now') AND LOWER(COALESCE(S.SIGLA_CAMPUS, '')) = 'uru' AND S.GENERO IS NOT NULL GROUP BY S.GENERO ORDER BY COUNT(*) DESC LIMIT 1